import{_ as o,c as t,a2 as i,o as l}from"./chunks/framework.BQmytedh.js";const n="/assets/image-9.C17nHAj4.png",c="/assets/image-10.C65xvhtz.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pages/点滴想法/用户访问Nginx网站发生了什么.md","filePath":"pages/点滴想法/用户访问Nginx网站发生了什么.md","lastUpdated":1732945848000}'),a={name:"pages/点滴想法/用户访问Nginx网站发生了什么.md"};function s(d,e,p,r,g,_){return l(),t("div",null,e[0]||(e[0]=[i('<p><img src="'+n+'" alt="alt text"></p><hr><ul><li>用户访问Nginx网站发生了什么？</li></ul><blockquote><p>本文从前端到后台服务器的访问流程，简单介绍了访问一个nginx网站发生的步骤。</p></blockquote><ul><li>让我们画个图来看看吧</li></ul><p><img src="'+c+'" alt="alt text"></p><ol><li>例如用户从浏览器发起 <code>api.izqy.top</code>的访问，浏览器会先向 <code>DNS服务器</code> 查询 <code>api.izqy.top</code> 对应的IP</li><li>DNS服务器将查询到的IP地址<code>47.106.240.108</code>返回给浏览器</li><li>浏览器将携带 <strong>“域名”</strong> 信息和**“请求”**信息等数据发送到 <code>47.106.240.108</code> 对于的服务器对于的<code>80</code>端口所在的进程（这里是nginx进程，默认使用80端口）</li><li><code>nginx</code> 进程接收到请求信息后，首先从自己的配置信息表里查询 <strong>“域名”</strong> 信息<code>api.izqy.top</code>对应的反向代理服务，如果存在多个，就根据对应的负载均衡规则选择反向代理服务</li><li>根据获取到的反向代理服务信息，将**“请求”**信息发送给选择的反向代理服务</li><li>服务处理**“请求”**信息，完成后将信息返回给<code>nginx</code></li><li><code>nginx</code> 将 服务返回的信息，再转发给浏览器</li><li>浏览器解析返回的信息，展示给用户</li></ol>',7)]))}const u=o(a,[["render",s]]);export{m as __pageData,u as default};
